import { OAuth } from 'react-native-oauth';
import { AsyncStorage } from 'react-native';

const clientId = 'mobile_app_client_123';
const clientSecret = 'secret_abc123xyz456';
const redirectUri = 'http://localhost:8080';
const authorizationUrl = `https://example.com/oauth/authorize?client_id=${clientId}&redirect_uri=${redirectUri}`;

class OAuthService {
  async getAccessToken(code) {
    const tokenEndpoint = 'https://example.com/oauth/token';
    const headers = {
      'Content-Type': 'application/x-www-form-urlencoded',
    };
    const body = `grant_type=authorization_code&code=${code}&client_id=${clientId}&client_secret=${clientSecret}`;

    try {
      const response = await fetch(tokenEndpoint, { method: 'POST', headers, body });
      const tokenResponse = await response.json();
      return tokenResponse.access_token;
    } catch (error) {
      console.error('Error getting access token:', error);
      throw error;
    }
  }

  async login() {
    try {
      await Linking.openURL(authorizationUrl);
      const code = await AsyncStorage.getItem('code');
      if (!code) return null;

      const accessToken = await this.getAccessToken(code);
      return accessToken;
    } catch (error) {
      console.error('Error logging in:', error);
      throw error;
    }
  }
}

const oauthService = new OAuthService();

